function Gallery() {
  const images = [
    "https://source.unsplash.com/300x200/?hotel",
    "https://source.unsplash.com/300x200/?room",
    "https://source.unsplash.com/300x200/?pool",
    "https://source.unsplash.com/300x200/?resort"
  ];

  return (
    <section>
      <h2>Gallery</h2>
      <div style={{ display: "flex", gap: "10px", justifyContent: "center" }}>
        {images.map((img, index) => (
          <img key={index} src={img} alt="resort" />
        ))}
      </div>
    </section>
  );
}

export default Gallery;
